import {BeSkill} from '@be/be-framework';

export default class Analytics {
    private skill:BeSkill;
    private itemsViewed:number;
    private itemsOpened:number;
    private wasOpened:boolean;
    private itemWasDeleted:boolean;
    
    constructor(skill:BeSkill) {
        this.skill = skill;
        this.itemsViewed = 0;
        this.itemsOpened = 0;
        this.wasOpened = false;
        this.itemWasDeleted = false;
    }
    
    public opened() {
        this.skill.track('Gallery Opened');
        this.itemsViewed = 0;
        this.itemsOpened = 0;
        this.wasOpened = true;
        this.itemWasDeleted = false;
    }
    
    public itemViewed() {
        this.itemsViewed++;
    }
    
    public itemOpened() {
        this.itemsOpened++;
        this.itemViewed();
    }
    
    public itemDeleted() {
        this.itemWasDeleted = true;
    }
    
    public finished() {
        if (this.wasOpened) {
            this.skill.track('Gallery Finished', {
                items_viewed:this.itemsViewed,
                items_opened:this.itemsOpened,
                photo_deleted:this.itemWasDeleted
            });
            this.wasOpened = false;
        }
    }
}