import jibo = require('jibo');
import MenuView = jibo.rendering.gui.views.MenuView;
import ActionData = jibo.rendering.gui.actions.ActionData;
import List = jibo.rendering.gui.components.List;
import Notifier from '../utils/Notifier';

export default class ItemView extends MenuView {
    private _choiceBtn:jibo.rendering.gui.components.MenuButton;

    constructor(viewState?:any) {
        super(viewState);

        this.onItemsDeleted = this.onItemsDeleted.bind(this);
    }

    public actionEnactor(action:ActionData):boolean {
        if (action.type === ActionData.VERBAL_COMMAND) {
            switch(action.data.intent) {
                case 'pause':
                    //select the currently on screen item, same as if it had been a tap
                    return super.actionEnactor(new ActionData(action.type, new jibo.jetstream.types.ListenResult(null, {intent:'selectItem', entities: {}, rules: []})));
            }
        }
        return super.actionEnactor(action);
    }

    public actionHandler(action:ActionData, fromComponent?:any):void {
        const component = this._list.getComponentByIndex(this._list.pageIndex);
        //intercept paged events to add data
        if (action.type === ActionData.EVENT && action.data.event === List.PAGED) {
            action.data.itemId = component.id;
            action.data.index = this._list.pageIndex;
        }
        super.actionHandler(action, fromComponent);
    }

    public applyData():void {
        // load sfx
        this.addAssetDescriptorObject(
            {
                id: 'delete-sfx',
                type: 'sound',
                src: 'audio/delete.m4a'
            }
        );
        // add clip for save or delete icon to be used atop photo
        this._choiceBtn = new jibo.rendering.gui.components.MenuButton();
        this._choiceBtn.addAssetDescriptorObject(
            {
                id: 'delete',
                type: 'texture',
                src: 'core://resources/actionIcons/delete.png',
                cache: 'global-gui'
            }
        );

        this._choiceBtn.interactable = false;
        this._choiceBtn.applyButtonType(jibo.rendering.gui.components.MenuButton.ACTION);

        this.addComponent(this._choiceBtn, 'choiceBtn');

        super.applyData();
    }

    public ready():void {
        super.ready();

        //remove button from stage so we don't render it
        const display = this._choiceBtn.display;
        display.parent.removeChild(display);
        //center button
        display.pivot.x = this._choiceBtn.dimensions.width / 2;
        display.pivot.y = this._choiceBtn.dimensions.height / 2;
        // set color to red, icon to trash
        this._choiceBtn.setIcon(new PIXI.Sprite(this.assets['delete']));
        this._choiceBtn.colors = 'cancel';

        Notifier.deleted.on(this.onItemsDeleted);
    }

    public removeItem(id:string):Promise<void> {
        return new Promise<void>((resolve) => {
            //remove any pause overlay
            this.pause(false);
            //disable input - don't want anybody interfering during the removal process
            this.lockInput(true);

            this.list.removeComponent(id, () => {
                //note - leaving the list disabled, because we want to let the Menu behavior
                //restore that when it starts back up
                resolve();
            }, this.itemRemovalTransition.bind(this));
        });
    }

    public itemRemovalTransition(item:jibo.rendering.gui.components.Element, done:()=>void): void {
        // show save or delete sprite, play SFX
        let action:jibo.rendering.gui.actions.ActionData = new jibo.rendering.gui.actions.ActionData('sound', {id:'delete-sfx'});

        let choiceDisplay:PIXI.Container = this._choiceBtn.display;
        let btnDisplay:PIXI.Container = this._choiceBtn.buttonDisplay;
        item.display.x = item.display.pivot.x = item.display.width / 2;
        item.display.y = item.display.pivot.y = item.display.height / 2;
        //add the button to the item and center it
        item.display.addChild(choiceDisplay);
        choiceDisplay.x = item.display.x;
        choiceDisplay.y = item.display.y;
        // play sound, have to unlock input, should allow override in actionHandler
        this._inputLocked = false;
        super.actionHandler(action);
        this._inputLocked = true;

        // start tween
        const TweenManager = jibo.face.tween;
        // tween alpha - don't wait on it for anything
        TweenManager.play(
            btnDisplay,
            {
                to: {alpha: 1},
                from: {alpha: 0},
                duration: 500,
                ease: 'sineIn'
            }
        );
        TweenManager.play(
            btnDisplay,
            {
                to: {
                    'scale.x': 1,
                    'scale.y': 1
                },
                from: {
                    'scale.x': 0,
                    'scale.y': 0
                },
                duration: 750,
                ease: 'backOut'
            },
            () => {
                //now, transition the whole item out
                const tweenTime = 550;
                // tween alpha - again, don't wait on it
                TweenManager.play(item.display,
                    {
                        to: {alpha: 0},
                        duration: tweenTime,
                        ease: 'sineIn'
                    }
                );
                TweenManager.play(item.display,
                    {
                        to: {
                            'scale.x': 0,
                            'scale.y': 0
                        },
                        duration: tweenTime,
                        ease: 'backIn'
                    },
                    () => {
                        //ensure tween is stopped because item is about to get destroyed
                        TweenManager.stop(item.display);
                        item.display.alpha = 0;
                        //remove button from item, so we can reuse it
                        choiceDisplay.parent.removeChild(choiceDisplay);
                        //now we are done
                        done();
                    }
                );
            }
        );
    }

    close(callback?, transitionType?) {
        Notifier.deleted.removeListener(this.onItemsDeleted);

        super.close(callback, transitionType);
    }

    private onItemsDeleted(deleted:string[]):void {
        //because we can't delete many items at once currently, delete one at a time
        //most of the time it shouldn't be a problem anyway
        let prom:Promise<void> = Promise.resolve();
        prom = prom.then(() => {
            return new Promise<void>((resolve) => {
                const id = deleted.shift();
                if (jibo.face.views.currentView !== this && id === this.list.getComponentByIndex(this.list.pageIndex).id) {
                    jibo.face.views.changeView({removeTo: this.id}, () => {
                        resolve();
                    });
                    this.list.removeComponent(id);
                } else {
                    this.list.removeComponent(id, () => {
                        resolve();
                    });
                }
            });
        });
    }
}
