import jibo = require('jibo');
import Button = jibo.rendering.gui.components.Button;

const DIMENSIONS = new PIXI.Point(1280, 720);

export default class ImageItem extends Button {
    public static get DEFAULT_TYPE():string {return 'ImageItem';}
    
    protected _type = ImageItem.DEFAULT_TYPE;
    
    public dimensions:PIXI.Point = DIMENSIONS;
    
    public static createFromConfig(configData:any):ImageItem {
        let btn:ImageItem = new ImageItem();
        btn.assignConfig(configData);
        return btn;
    }
    
    public assignConfig(configData:any):void {
        if(configData){
            super.assignConfig(configData);
            
            // add asset descriptor for image
            this.addAssetDescriptor(this.id, configData.imageSrc, 'texture');
        }
    }
    
    public setupDisplay(assets?:any):void {
        const tex:PIXI.Texture = assets[this.id];
        let image:PIXI.Sprite = new PIXI.Sprite(tex || PIXI.Texture.EMPTY);
        this.display.addChild(image);
        
        this.setupHitArea(new PIXI.Rectangle(0, 0, 1280, 720));
        this.setupInteractions();
    }
}