import {libraries} from '@be/be-framework';
import Event = libraries.jibo_typed_events.Event;

const Notifier = {
    deleted: new Event<string[]>('Item(s) Deleted'),
    allDeleted: new Event<void>('All Items Deleted')
};

export default Notifier;

export function cleanNotifications() {
    Notifier.allDeleted.removeAllListeners();
    Notifier.deleted.removeAllListeners();
};