/// <reference path="../typings/index.d.ts" />
import jibo = require('jibo');
import {BeSkill, Options} from '@be/be-framework';
import {buildThumbList, buildItemList} from './utils/BuildItemList';
import * as gui from './gui';
import * as media from './utils/media';
import List = jibo.rendering.gui.components.List;
import Notifier, {cleanNotifications} from './utils/Notifier';
import Analytics from './analytics/Analytics';
import logWrap from './utils/log';

const deleteItemFlow = require('./flows/deleteItem');

class Gallery extends BeSkill {
    //for unit tests
    private flowOverrides:any = null;
    //actual runtime variables
    private fromMainMenu:boolean;
    private activeFilter:string = 'all';
    private mainFlow:jibo.flow.FlowExecutor;
    private analytics:Analytics;

    /**
     * Gallery skill constructor
     * @constructor
     * @param {String} [assetPack=''] The asset pack if loading from Be
     */
    constructor(assetPack?:Options) {
        super(assetPack);

        this.analytics = new Analytics(this);

        logWrap.log = this.log.createChild('Utils');
    }

    preload(done:(err?:any)=>void):void {
        done();
    }

    /**
     * Start the skill
     * @method open
     */
    open(result?:any, refresh?:boolean):void {
        if (refresh) {
            this.close(() => {
                this._openHelper(result);
            });
        } else {
            this._openHelper(result);
        }
    }

    _openHelper(result?:any) {
        gui.register();

        this.fromMainMenu = result && result.intent === 'menu';

        const options = Object.assign({
            enableLogging: false,
            assetPack: this.assetPack,
            blackboard: {
                media: media,
                userData: null,
                analytics: this.analytics,
                parentLog: this.log.createChild('Flows'),
                buildThumbList,
                buildItemList,
                Notifier
            }
        },
            this.flowOverrides
        );

        this.mainFlow = jibo.flow.run(require('./flows/main'), options, (err, status) => {
            if (status === jibo.bt.Status.INTERRUPTED) {
                return;
            }
            if (this.mainFlow.blackboard.userData) {
                this.mainFlow.blackboard.userData.destroy();
            }
            const result = this.mainFlow.result.transition;
            this.mainFlow.destroy();
            this.mainFlow = null;
            if (result === 'return' && this.fromMainMenu) {
                this.log.debug('closing and redirecting to main menu');
                this.redirect('@be/main-menu', {});
            } else if (result === 'create') {
                this.redirect('@be/create', {nlu:{intent:'createOnePhoto'}});
                this.log.debug('closing and redirecting to create');
            } else {
                this.log.debug('closing - no redirect');
                this.exit();
            }
        });
    }

    /**
     * Stop and unload the skill
     * @method close
     */
    close(done:() => void):void {
        gui.unregister();
        this.analytics.finished();

        if (this.mainFlow) {
            cleanNotifications();
            if (this.mainFlow.blackboard.userData) {
                this.mainFlow.blackboard.userData.destroy();
            }

            Promise.all([
                //stop the main flow
                this.mainFlow.stop()
                .catch((err) => {
                    this.log.debug('Error when stopping flow: ', err);
                })
                .then(() => {
                    this.mainFlow.destroy();
                    this.mainFlow = null;
                }),

                //Be 150% sure that we removed all of our views, as it is possible to leave
                //non-active views in the stack
                new Promise((resolve) => {
                    jibo.face.views.changeView({removeAll: true, leaveEmpty: true, transitionClose: jibo.face.views.DOWN}, () => {
                        resolve();
                    }, () => {
                        resolve();
                    });
                })
                .catch((err) => {
                    this.log.debug('had an error when closing views: ', err);
                })
            ])
            .then(() => {
                done();
            });
        } else {
            done();
        }
    }
}

module.exports = Gallery;
