import jibo = require('jibo');
import {utils} from '@be/be-framework';
import * as media from './media';
import UserData from './UserData';
import MediaNode = jibo.kb.media.MediaNode;

export function buildThumbList(userData: UserData, filter:string = 'all') {
    
    let list:any = {
        viewConfig: {
            type: "GalleryListView",
            dynamic: true,
            id: "gallery_list",
            title: "Gallery",
            activeFilter:filter,
            listDefault: {
                type: "ContentButton"
            },
            list: []
        },
        //standard open is transition from the bottom, this will be overridden if appropriate
        open: {
            transitionOpen:"trans_up"
        },
        //if the user closes this view, then leave the view empty - we could be going back to idle
        //or the main menu
        defaultClose: {
            remove: true,
            leaveEmpty: true,
            transitionClose:"trans_down"
        },
        //leave the list on screen, so that the item view can be loading while this list view
        //transitions off screen
        defaultSelect: "remain",
        //will be filled in by the calling code, that knows if we are first opening or returning
        baseMim: null
    };
    
    const data = userData.data;
    for (let i = 0; i < data.length; ++i) {
        let thumbnailId:string = data[i].getThumbnailId();
        let mediaId:string = data[i].id;
        let dateCreated:number = data[i].data.created;
        //TODO: filter these based on photo/photobooth - I don't know if we are able to tell
        //those from each other right now, because we don't have arbitrary metadata
        let labelDate = new utils.DateTime(dateCreated, utils.Location.jiboHome.timezone);
        list.viewConfig.list.push({
            id: mediaId,
            type: "ContentButton",
            label: labelDate.toMoment(),
            iconSrc: media.getUrl(thumbnailId),
            action: {
                type: "event",
                data: {
                    event: "press",
                    id: mediaId
                }
            }
        });
    }
    
    return list;
}

export function buildItemList(userData: UserData, startOnItem:string) {
    
    let list:any = {
        viewConfig: {
            type: "GalleryItemView",
            dynamic: true,
            id: "gallery_items",
            elementsPerPage: 1,
            list: []
        },
        //standard open is transition from the bottom, this will be overridden if appropriate
        open: {
            transitionOpen:"trans_up"
        },
        //leave the list on screen, so that the list view can be loading while the item view
        //transitions off screen
        defaultClose: "remain",
        //leave the list on screen, so that the item view can be loading while this list view
        //transitions off screen
        defaultSelect: "remain",
        rule: 'gallery/item_view',
        timeout: 120
    };
    
    const data = userData.data;
    for (let i = 0; i < data.length; ++i) {
        let mediaId:string = data[i].id;
        list.viewConfig.list.push({
            id: mediaId,
            type: "ImageItem",
            imageSrc: media.getUrl(mediaId),
            action: {
                type: "event",
                data: {
                    event: "press",
                    id: mediaId
                }
            }
        });
        if (startOnItem === mediaId) {
            list.viewConfig.pageIndex = i;
        }
    }
    
    return list;
}