import jibo = require('jibo');
import ListView from './ListView';
import ItemView from './ItemView';
import ImageItem from './ImageItem';
import ItemPauseView from './ItemPauseView';

export function register() {
    jibo.face.views.creator.registerClass(ListView, 'GalleryListView');
    jibo.face.views.creator.registerClass(ItemView, 'GalleryItemView');
    jibo.face.views.creator.registerClass(ImageItem, 'ImageItem');
    jibo.face.views.creator.registerClass(ItemPauseView, 'GalleryItemPauseView');
}

export function unregister() {
    jibo.face.views.creator.unregisterClass('GalleryListView');
    jibo.face.views.creator.unregisterClass('GalleryItemView');
    jibo.face.views.creator.unregisterClass('ImageItem');
    jibo.face.views.creator.unregisterClass('GalleryItemPauseView');
}