import jibo = require('jibo');
import MediaNode = jibo.kb.media.MediaNode;
import Notifier from './Notifier';

export default class UserData {
    public data: MediaNode[];
    private log:typeof jibo.log;
    
    public get isEmpty():boolean {
        return !(this.data && this.data.length > 0);
    }
    
    public get length():number {
        return this.data ? this.data.length : 0;
    }
    
    constructor(parentLog:typeof jibo.log, data?: MediaNode[]) {
        this.data = data || null;
        this.onMediaChanged = this.onMediaChanged.bind(this);
        this.log = parentLog.createChild('UserData');
    }
    
    public init():Promise<this> {
        let start = Date.now();
        return jibo.kb.media.loadMedia().then((data) => {
            this.log.debug(`Took ${Date.now() - start}ms to fetch Gallery content. Total items:`, data.length);
            start = Date.now();
            //filter out non-images, so we aren't tracking thumbnails too
            data = data.filter((item) => {
                //filter out images with no edges - test data from test credentials?
                if (!item.edges) {
                    return false;
                }
                return item.data.type === jibo.kb.media.MediaType.image;
            });
            
            //newest to oldest
            data.sort((a, b) => {
                return b.data.created - a.data.created;
            });
            this.log.debug(`Took ${Date.now() - start}ms to filter and sort Gallery content (synchronously). Total photos:`, data.length);
            
            //store the data
            this.data = data;
            //start listening for changes
            jibo.kb.media.events.mediaListChanged.on(this.onMediaChanged);
            
            return this;
        });
    }
    
    public destroy() {
        this.data = null;
        jibo.kb.media.events.mediaListChanged.removeListener(this.onMediaChanged);
    }
    
    private onMediaChanged() {
        this.log.debug('Media changed - fetching media list to check for deletions');
        //start the process of comparing changed media to find out what changed and figure out
        //what to do about it
        jibo.kb.media.loadMedia().then((data) => {
            //filter out non-images, so we aren't tracking thumbnails too
            data = data.filter((item) => {
                //filter out images with no edges - test data from test credentials?
                if (!item.edges) {
                    return false;
                }
                return item.data.type === jibo.kb.media.MediaType.image;
            });
            
            //if no data, then bail
            if (!data.length) {
                this.log.debug('After fetching media list, all items deleted!');
                this.data = data;
                Notifier.allDeleted.emit();
                return;
            }
            
            //newest to oldest
            data.sort((a, b) => {
                return b.data.created - a.data.created;
            });
            //this works on the assumption that things can only be deleted from outside the robot
            //you can't use Create while in the Gallery, so we shouldn't see stuff get added in ever
            
            //look for what got deleted and track that
            const deleted:string[] = [];
            
            const currentData = this.data;
            //track everything that is still there
            const inUse:{[id:string]:boolean} = {};
            for (let i = 0, length = data.length; i < length; ++i) {
                inUse[data[i].id] = true;
            }
            //now go through the old list and see what is missing
            for (let i = 0, length = currentData.length; i < length; ++i) {
                const id = currentData[i].id;
                if (!inUse[id]) {
                    deleted.push(id);
                }
            }
            this.log.debug(`After fetching media list, number of deleted items: ${deleted.length}`);
            
            if (deleted.length > 0) {
                this.data = data;
                Notifier.deleted.emit(deleted);
            }
        }).catch((err) => {
            this.log.warn('Caught error when loading media to delete item:', err);
        });
    }
}
