import jibo = require('jibo');
import MediaNode = jibo.kb.media.MediaNode;
import ItemView from '../gui/ItemView';
import UserData from './UserData';
import logWrap from './log';

let log:typeof jibo.log = null;

//wrapper for jibo.media.getUrl that allows us to intercept testing ids
export function getUrl(id:string):string {
    return jibo.media.getUrl(id);
}

//gets test or real data
export async function getMedia():Promise<UserData> {
    if (!log) {
        log = logWrap.log.createChild('media');
    }
    const data = new UserData(logWrap.log);
    return data.init();
}

//Deletes an item from the loop's saved media, then if successful, removes that item from the
//userData array (make sure you pass it in by reference, not a copy!)
export async function deleteItem(itemToDelete:string, userData:UserData) {
    //remove the item from the list of items to keep up to date
    const index = userData.data.findIndex((item) => {
        return item.id === itemToDelete;
    });
    if (index > -1) {
        userData.data.splice(index, 1);
    }
    
    //set up some variables to hold promises for a Promise.all()
    let viewProm:Promise<void>;
    let deleteProm:Promise<void>;
    //get the item view to remove stuff
    let view:jibo.rendering.gui.views.View = jibo.face.views.currentView;
    while(view && view.id !== 'gallery_items') {
        view = view.pausedParent;
    }
    if (view) {
        viewProm = (view as ItemView).removeItem(itemToDelete);
    } else {
        viewProm = Promise.resolve();
    }
    let start = Date.now();
    //delete photo off of disk, kb, and cloud
    deleteProm = jibo.media.deletePhoto(itemToDelete).then(() => {
        log.debug(`Took ${Date.now() - start}ms to delete item.`);
    }, (err) => {
        log.warn('Unable to delete item: ', err);
        return Promise.reject(err);
    });
    
    return Promise.all([viewProm, deleteProm]);
}